/**
 * The starter's files, as pure functions of the project name.
 *
 * Each function returns one file's contents as a string. They are deliberately
 * pure and side-effect free: `scaffold` owns all I/O, these own all content, so
 * the generated bytes are tested directly without touching a disk.
 *
 * The app they emit is small but REAL — it boots on `@keel/kernel`'s `createApp`
 * with a Post model, a migration, a controller, and a router, mirroring the
 * shape of the canonical blog example.
 */

/**
 * The version specifier every `@keel/*` dependency is scaffolded with.
 *
 * A real npm dist-tag, resolvable by any package manager outside this monorepo —
 * deliberately NOT the `workspace:*` protocol, which only resolves in-workspace.
 */
const keelDep = "latest";

/** `package.json` for the scaffolded app: starter deps + a `keel dev` script. */
export function packageJson(name: string): string {
  const manifest = {
    name,
    version: "0.0.0",
    type: "module",
    private: true,

    scripts: {
      dev: "keel dev",
    },

    dependencies: {
      // Resolvable specifiers for a freshly scaffolded app: `latest` is a real
      // npm dist-tag that any package manager can install OUTSIDE this monorepo.
      // The `workspace:*` protocol resolves only within the workspace, so a
      // generated app would fail to install — emit `latest` instead.
      "@keel/kernel": keelDep,
      "@keel/migrate": keelDep,
      "@keel/orm": keelDep,
      "@keel/router": keelDep,
      "@keel/runtime": keelDep,
      "@keel/ui": keelDep,
      "@keel/web": keelDep,
      "better-sqlite3": "^11.10.0",
      react: "^19",
      "react-dom": "^19",
    },
  };

  return `${JSON.stringify(manifest, null, 2)}\n`;
}

/**
 * `keel.app.ts` — the project root's entrypoint.
 *
 * It default-exports an `AppConfig` (the `{ db, router, controllers, migrations }`
 * object `createApp` accepts), which `@keel/cli`'s `keel dev` loads and boots.
 */
export function keelApp(): string {
  return `/**
 * The app: a Post model, its migration, a controller, and a router, wired into
 * the AppConfig that \`keel dev\` boots. This is the whole application — grow it
 * by adding models, migrations, controllers, and routes.
 */

import { Model } from "@keel/orm";
import type { ValidationRules } from "@keel/orm";

import type { MigrationEntry } from "@keel/migrate";

import { Router } from "@keel/router";

import { Controller } from "@keel/web";
import type { AppConfig, KernelDatabase } from "@keel/kernel";
import type { KeelResponse } from "@keel/web";

import { createRequire } from "node:module";

// The Post model: the class name \`Post\` maps to the table \`posts\`.
export class Post extends Model {
  static override timestamps = true;

  static override validations: ValidationRules = {
    title: { presence: true },
  };
}

// The schema, version-stamped and idempotent — run on boot by the kernel.
const createPosts: MigrationEntry = {
  version: "001_create_posts",
  migration: {
    up: (schema) => {
      schema.createTable("posts", (t) => {
        t.string("title", { null: false });
        t.text("body", { null: false });
        t.timestamps();
      });
    },

    down: (schema) => {
      schema.dropTable("posts");
    },
  },
};

// The controller: one JSON action over every Post.
export class PostsController extends Controller {
  index(): KeelResponse {
    const posts = Post.order("id", "asc")
      .all()
      .map((post) => post.toJSON());

    return this.json({ posts });
  }
}

// The routes: the seven RESTful routes for the posts collection.
function buildRouter(): Router {
  const router = new Router();

  router.resources("posts");

  return router;
}

/**
 * The driver seam: better-sqlite3 under Node, \`bun:sqlite\` under Bun.
 *
 * better-sqlite3's native addon cannot \`dlopen\` under Bun, so the specifier is
 * assembled at runtime and the built-in is dynamically imported as a fallback.
 */
interface SqliteHandle {
  exec(sql: string): unknown;
  prepare(sql: string): {
    run(...params: unknown[]): { changes: number; lastInsertRowid: number | bigint };
    get(...params: unknown[]): unknown;
    all(...params: unknown[]): unknown[];
  };
}

function tryBetterSqlite(filename: string): SqliteHandle | undefined {
  try {
    const require = createRequire(import.meta.url);
    const Database = require("better-sqlite3") as new (file: string) => SqliteHandle;

    return new Database(filename);
  } catch {
    // Native binding unavailable under this runtime (e.g. Bun) — fall back.
    return undefined;
  }
}

async function bunSqlite(filename: string): Promise<SqliteHandle> {
  const specifier = ["bun", "sqlite"].join(":");

  const { Database } = (await import(specifier)) as {
    Database: new (file: string) => SqliteHandle;
  };

  return new Database(filename);
}

async function openDatabase(filename = "keel.db"): Promise<KernelDatabase> {
  const raw = tryBetterSqlite(filename) ?? (await bunSqlite(filename));

  return {
    exec: (sql) => raw.exec(sql),
    prepare: (sql) => {
      const statement = raw.prepare(sql);

      return {
        run: (params = []) => statement.run(...params),
        get: (params = []) => statement.get(...params),
        all: (params = []) => statement.all(...params),
      };
    },
  };
}

const config: AppConfig = {
  db: await openDatabase(),
  router: buildRouter(),
  controllers: { posts: PostsController },
  migrations: [createPosts],
};

export default config;
`;
}

/** `tsconfig.json` for the scaffolded app: strict, ESM, bundler resolution. */
export function tsconfig(): string {
  const config = {
    compilerOptions: {
      target: "ES2023",
      lib: ["ES2023"],
      module: "ESNext",
      moduleResolution: "Bundler",
      verbatimModuleSyntax: true,
      isolatedModules: true,
      resolveJsonModule: true,
      strict: true,
      jsx: "react-jsx",
      types: ["node"],
      skipLibCheck: true,
    },
    include: ["keel.app.ts"],
  };

  return `${JSON.stringify(config, null, 2)}\n`;
}

/** `.gitignore` — keep build artefacts and the local SQLite file out of git. */
export function gitignore(): string {
  return ["node_modules/", "*.db", "*.db-journal", "dist/", ".DS_Store", ""].join("\n");
}

/** `README.md` — how to run the freshly scaffolded app. */
export function readme(name: string): string {
  return `# ${name}

A Keel app — batteries included.

## Develop

\`\`\`sh
bun install
bun run dev
\`\`\`

\`keel dev\` loads \`keel.app.ts\` (which default-exports the app config) and boots
it: the kernel connects the ORM, runs migrations, and stands up request dispatch.

## Structure

- \`keel.app.ts\` — the whole app: a \`Post\` model, its migration, a
  \`PostsController\`, and a router with \`resources("posts")\`.
`;
}
